--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ ... @@
+// ─── Wall Decorations ─────────────────────────────────────────────
+
+function drawBannerDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  drawBanner(ctx, x, y, 18 * scale, 38 * scale, '#8b1515', P.gold[3]);
+}
+
+function drawShieldDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  ctx.fillStyle = '#2a4080';
+  ctx.beginPath();
+  ctx.moveTo(10, 2);
+  ctx.lineTo(20, 6);
+  ctx.lineTo(20, 20);
+  ctx.lineTo(15, 26);
+  ctx.lineTo(10, 20);
+  ctx.lineTo(0, 6);
+  ctx.closePath();
+  ctx.fill();
+  ctx.fillStyle = P.gold[3];
+  ctx.fillRect(8, 10, 6, 2);
+  ctx.fillRect(10, 6, 2, 14);
+  ctx.restore();
+}
+
+function drawWeaponDisplayDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  drawWeaponRack(ctx, x, y, scale);
+}
+
+function drawPaintingDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  ctx.fillStyle = '#4a2810';
+  ctx.fillRect(0, 0, 24, 18);
+  ctx.fillStyle = '#5c3418';
+  ctx.fillRect(2, 2, 20, 14);
+  ctx.fillStyle = '#8b1a1a';
+  ctx.fillRect(4, 4, 16, 10);
+  ctx.fillStyle = '#a02525';
+  ctx.fillRect(6, 6, 12, 6);
+  ctx.restore();
+}
+
+function drawSconceDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number, frame: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  // Base
+  ctx.fillStyle = '#4a2810';
+  ctx.fillRect(0, 0, 6, 12);
+  ctx.fillStyle = '#5c3418';
+  ctx.fillRect(1, 1, 4, 10);
+  // Flame
+  const f1 = Math.sin(frame * 0.3) * 1.5;
+  ctx.fillStyle = '#f0b040';
+  ctx.beginPath();
+  ctx.moveTo(3, 0);
+  ctx.lineTo(6, 6 + f1);
+  ctx.lineTo(0, 6 - f1);
+  ctx.closePath();
+  ctx.fill();
+  ctx.restore();
+}
+
+export function drawWallDecoration(
+  ctx: CanvasRenderingContext2D,
+  type: 'banner' | 'shield' | 'weaponDisplay' | 'painting' | 'sconce',
+  x: number,
+  y: number,
+  scale: number,
+  frame: number,
+) {
+  switch (type) {
+    case 'banner':
+      drawBannerDecoration(ctx, x, y, scale);
+      break;
+    case 'shield':
+      drawShieldDecoration(ctx, x, y, scale);
+      break;
+    case 'weaponDisplay':
+      drawWeaponDisplayDecoration(ctx, x, y, scale);
+      break;
+    case 'painting':
+      drawPaintingDecoration(ctx, x, y, scale);
+      break;
+    case 'sconce':
+      drawSconceDecoration(ctx, x, y, scale, frame);
+      break;
+  }
+}
+
+// ─── Integration into rooms ───────────────────────────────────────
+
+function drawRoomWallDecorations(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number, frame: number) {
+  switch (type) {
+    case 'king':
+      // Banners left and right walls
+      drawWallDecoration(ctx, 'banner', x + w * 0.08, y + 4, 1, frame);
+      drawWallDecoration(ctx, 'banner', x + w * 0.82, y + 4, 1, frame);
+      break;
+    case 'knight':
+      // Shield and weapon display on wall
+      drawWallDecoration(ctx, 'shield', x + w * 0.15, y + h * 0.1, 1, frame);
+      drawWallDecoration(ctx, 'weaponDisplay', x + w * 0.25, y + h * 0.12, 1, frame);
+      break;
+    case 'nobility':
+      // Tapestry already drawn, add sconces
+      drawWallDecoration(ctx, 'sconce', x + w * 0.05, y + h * 0.1, 1, frame);
+      drawWallDecoration(ctx, 'sconce', x + w * 0.9, y + h * 0.1, 1, frame);
+      break;
+    case 'scribe':
+      // Paintings on walls
+      drawWallDecoration(ctx, 'painting', x + w * 0.05, y + h * 0.05, 1, frame);
+      drawWallDecoration(ctx, 'painting', x + w * 0.7, y + h * 0.05, 1, frame);
+      break;
+    case 'judge':
+      // Sconces near torch
+      drawWallDecoration(ctx, 'sconce', x + w * 0.1, y + h * 0.15, 1, frame);
+      drawWallDecoration(ctx, 'sconce', x + w * 0.85, y + h * 0.15, 1, frame);
+      break;
+    case 'blacksmith':
+      // Weapon display on wall
+      drawWallDecoration(ctx, 'weaponDisplay', x + w * 0.1, y + h * 0.15, 1, frame);
+      break;
+    default:
+      break;
+  }
+}
+
+// Patch drawRoomFurniture to include wall decorations
+const originalDrawRoomFurniture = drawRoomFurniture;
+function patchedDrawRoomFurniture(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number, frame: number) {
+  originalDrawRoomFurniture(ctx, type, x, y, w, h, frame);
+  drawRoomWallDecorations(ctx, type, x, y, w, h, frame);
+}
+
+// Override export
+export { patchedDrawRoomFurniture as drawRoomFurniture };
+
